from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.allocation_decision import (
    AllocationDecision,
    AllocationDecisionError,
)
from src.trader.execution.allocation_decision_store import (
    AllocationDecisionStoreRecord,
    AllocationDecisionStoreError,
    replay_allocation_decision_by_id,
    replay_allocation_decisions_by_cycle,
)


class AllocationReplayReportError(RuntimeError):
    """Raised when allocation replay report inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise AllocationReplayReportError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise AllocationReplayReportError(f"{name} must be a non-negative integer")
    if value < 0:
        raise AllocationReplayReportError(f"{name} must be a non-negative integer")
    return value


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise AllocationReplayReportError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise AllocationReplayReportError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise AllocationReplayReportError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise AllocationReplayReportError(f"{name} must be a non-negative number")
    return normalized


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise AllocationReplayReportError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item))
    return normalized


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise AllocationReplayReportError("metadata must be a mapping when provided")
    return dict(value)


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise AllocationReplayReportError(f"{name} is required")
    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise AllocationReplayReportError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise AllocationReplayReportError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise AllocationReplayReportError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


def _normalize_store_record(value: Any) -> AllocationDecisionStoreRecord:
    if isinstance(value, AllocationDecisionStoreRecord):
        return value
    try:
        return AllocationDecisionStoreRecord.from_dict(_mapping_from_value("store_record", value))
    except (AllocationDecisionStoreError, AllocationDecisionError, TypeError, ValueError) as exc:
        raise AllocationReplayReportError("store_record could not be normalized") from exc


def _normalize_decision(value: Any) -> AllocationDecision:
    if isinstance(value, AllocationDecision):
        return value
    if hasattr(AllocationDecision, "from_dict"):
        try:
            return AllocationDecision.from_dict(_mapping_from_value("allocation_decision", value))
        except (AllocationDecisionError, TypeError, ValueError) as exc:
            raise AllocationReplayReportError("allocation_decision could not be normalized") from exc
    raise AllocationReplayReportError("AllocationDecision.from_dict is not available")


def _resolve_replay_string_field(
    *,
    raw_item: Mapping[str, Any],
    candidate_payload: Mapping[str, Any],
    field_name: str,
    default_value: str,
    issues: List[str],
    transform: Optional[str] = None,
) -> str:
    raw_value = raw_item.get(field_name)
    if isinstance(raw_value, str) and raw_value.strip():
        value = raw_value.strip()
    else:
        candidate_value = candidate_payload.get(field_name)
        if isinstance(candidate_value, str) and candidate_value.strip():
            value = candidate_value.strip()
        else:
            issues.append(f"candidate field missing from replay source: {field_name}")
            value = default_value

    if transform == "lower":
        return value.lower()
    if transform == "upper":
        return value.upper()
    return value


def _resolve_replay_numeric_field(
    *,
    raw_item: Mapping[str, Any],
    candidate_payload: Mapping[str, Any],
    field_name: str,
    default_value: float,
    issues: List[str],
) -> float:
    raw_value = raw_item.get(field_name)
    source_value = raw_value if raw_value is not None else candidate_payload.get(field_name)
    if source_value is None:
        issues.append(f"candidate field missing from replay source: {field_name}")
        return default_value

    try:
        return _normalize_non_negative_float(field_name, source_value)
    except AllocationReplayReportError:
        issues.append(f"candidate field malformed in replay source: {field_name}")
        return default_value


@dataclass(frozen=True)
class AllocationReplayReportItem:
    allocation_candidate_id: str
    decision_status: str
    chain: str
    strategy_id: str
    symbol: str
    pair: str
    side: str
    proposed_exposure_usd: float
    reserved_capital_usd: float
    approval_reasons: List[str] = field(default_factory=list)
    block_reasons: List[str] = field(default_factory=list)
    explanation_lines: List[str] = field(default_factory=list)
    lineage_present: bool = False
    lineage_id: Optional[str] = None
    policy_reference: Optional[str] = None
    issues: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_replay_report_item_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocation_candidate_id = _require_non_empty_string(
            "allocation_candidate_id",
            self.allocation_candidate_id,
        )
        decision_status = _require_non_empty_string("decision_status", self.decision_status).upper()
        if decision_status not in {"APPROVED", "BLOCKED"}:
            raise AllocationReplayReportError("decision_status must be APPROVED or BLOCKED")

        chain = _require_non_empty_string("chain", self.chain).lower()
        strategy_id = _require_non_empty_string("strategy_id", self.strategy_id).lower()
        symbol = _require_non_empty_string("symbol", self.symbol).upper()
        pair = _require_non_empty_string("pair", self.pair).upper()
        side = _require_non_empty_string("side", self.side).upper()
        proposed_exposure_usd = _normalize_non_negative_float(
            "proposed_exposure_usd",
            self.proposed_exposure_usd,
        )
        reserved_capital_usd = _normalize_non_negative_float(
            "reserved_capital_usd",
            self.reserved_capital_usd,
        )
        approval_reasons = _normalize_string_list("approval_reasons", self.approval_reasons)
        block_reasons = _normalize_string_list("block_reasons", self.block_reasons)
        explanation_lines = _normalize_string_list("explanation_lines", self.explanation_lines)
        issues = _normalize_string_list("issues", self.issues)
        metadata = _normalize_metadata(self.metadata)
        lineage_id = (
            None if self.lineage_id is None
            else _require_non_empty_string("lineage_id", self.lineage_id)
        )
        policy_reference = (
            None if self.policy_reference is None
            else _require_non_empty_string("policy_reference", self.policy_reference)
        )

        if decision_status == "APPROVED":
            if reserved_capital_usd <= 0.0:
                raise AllocationReplayReportError(
                    "approved replay items must reserve positive capital"
                )
            if block_reasons:
                raise AllocationReplayReportError(
                    "approved replay items must not include block_reasons"
                )
        else:
            if reserved_capital_usd != 0.0:
                raise AllocationReplayReportError(
                    "blocked replay items must reserve zero capital"
                )
            if not block_reasons:
                raise AllocationReplayReportError(
                    "blocked replay items must include block_reasons"
                )

        if not explanation_lines:
            explanation_lines = [
                f"{decision_status.title()} {symbol} on {chain} via strategy {strategy_id}.",
                *[f"Reason: {reason}" for reason in approval_reasons],
                *[f"Block: {reason}" for reason in block_reasons],
            ]

        if not self.lineage_present:
            if lineage_id is not None:
                raise AllocationReplayReportError(
                    "lineage_id must be null when lineage_present is false"
                )
            if "missing lineage from replay source candidate" not in issues:
                issues.append("missing lineage from replay source candidate")

        object.__setattr__(self, "allocation_candidate_id", allocation_candidate_id)
        object.__setattr__(self, "decision_status", decision_status)
        object.__setattr__(self, "chain", chain)
        object.__setattr__(self, "strategy_id", strategy_id)
        object.__setattr__(self, "symbol", symbol)
        object.__setattr__(self, "pair", pair)
        object.__setattr__(self, "side", side)
        object.__setattr__(self, "proposed_exposure_usd", proposed_exposure_usd)
        object.__setattr__(self, "reserved_capital_usd", reserved_capital_usd)
        object.__setattr__(self, "approval_reasons", approval_reasons)
        object.__setattr__(self, "block_reasons", block_reasons)
        object.__setattr__(self, "explanation_lines", explanation_lines)
        object.__setattr__(self, "issues", issues)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(self, "lineage_id", lineage_id)
        object.__setattr__(self, "policy_reference", policy_reference)
        object.__setattr__(
            self,
            "allocation_replay_report_item_id",
            _stable_id(
                "allocation_replay_report_item",
                {
                    "allocation_candidate_id": allocation_candidate_id,
                    "decision_status": decision_status,
                    "symbol": symbol,
                    "reserved_capital_usd": reserved_capital_usd,
                    "lineage_present": self.lineage_present,
                    "lineage_id": lineage_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocation_candidate_id": self.allocation_candidate_id,
            "decision_status": self.decision_status,
            "chain": self.chain,
            "strategy_id": self.strategy_id,
            "symbol": self.symbol,
            "pair": self.pair,
            "side": self.side,
            "proposed_exposure_usd": self.proposed_exposure_usd,
            "reserved_capital_usd": self.reserved_capital_usd,
            "approval_reasons": list(self.approval_reasons),
            "block_reasons": list(self.block_reasons),
            "explanation_lines": list(self.explanation_lines),
            "lineage_present": self.lineage_present,
            "lineage_id": self.lineage_id,
            "policy_reference": self.policy_reference,
            "issues": list(self.issues),
            "metadata": dict(self.metadata),
            "allocation_replay_report_item_id": self.allocation_replay_report_item_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationReplayReportItem":
        if not isinstance(payload, Mapping):
            raise AllocationReplayReportError("payload must be a mapping")
        return cls(
            allocation_candidate_id=payload.get("allocation_candidate_id"),
            decision_status=payload.get("decision_status"),
            chain=payload.get("chain"),
            strategy_id=payload.get("strategy_id"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            proposed_exposure_usd=payload.get("proposed_exposure_usd"),
            reserved_capital_usd=payload.get("reserved_capital_usd"),
            approval_reasons=list(payload.get("approval_reasons") or []),
            block_reasons=list(payload.get("block_reasons") or []),
            explanation_lines=list(payload.get("explanation_lines") or []),
            lineage_present=bool(payload.get("lineage_present")),
            lineage_id=payload.get("lineage_id"),
            policy_reference=payload.get("policy_reference"),
            issues=list(payload.get("issues") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationReplayReport:
    allocator_cycle_id: str
    allocation_decision_id: str
    source_store_path: str
    source_appended_at_utc: str
    approved_count: int
    blocked_count: int
    total_reserved_capital_usd: float
    items: List[AllocationReplayReportItem] = field(default_factory=list)
    issues: List[str] = field(default_factory=list)
    summary_lines: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_replay_report_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocator_cycle_id = _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id)
        allocation_decision_id = _require_non_empty_string(
            "allocation_decision_id",
            self.allocation_decision_id,
        )
        source_store_path = _require_non_empty_string("source_store_path", self.source_store_path)
        source_appended_at_utc = _require_non_empty_string(
            "source_appended_at_utc",
            self.source_appended_at_utc,
        )
        approved_count = _normalize_non_negative_int("approved_count", self.approved_count)
        blocked_count = _normalize_non_negative_int("blocked_count", self.blocked_count)
        total_reserved_capital_usd = _normalize_non_negative_float(
            "total_reserved_capital_usd",
            self.total_reserved_capital_usd,
        )
        items = [
            item if isinstance(item, AllocationReplayReportItem)
            else AllocationReplayReportItem.from_dict(_mapping_from_value("item", item))
            for item in self.items
        ]
        issues = _normalize_string_list("issues", self.issues)
        summary_lines = _normalize_string_list("summary_lines", self.summary_lines)
        metadata = _normalize_metadata(self.metadata)

        derived_approved_count = sum(1 for item in items if item.decision_status == "APPROVED")
        derived_blocked_count = sum(1 for item in items if item.decision_status == "BLOCKED")
        derived_reserved_capital = sum(item.reserved_capital_usd for item in items)
        derived_item_issues = [issue for item in items for issue in item.issues]

        if approved_count != derived_approved_count:
            raise AllocationReplayReportError("approved_count does not match replay items")
        if blocked_count != derived_blocked_count:
            raise AllocationReplayReportError("blocked_count does not match replay items")
        if round(total_reserved_capital_usd, 8) != round(derived_reserved_capital, 8):
            raise AllocationReplayReportError(
                "total_reserved_capital_usd does not match replay items"
            )

        merged_issues = list(issues)
        for issue in derived_item_issues:
            if issue not in merged_issues:
                merged_issues.append(issue)

        if not summary_lines:
            summary_lines = [
                f"Allocator cycle {allocator_cycle_id} replayed from {source_store_path}.",
                f"Approved: {approved_count}.",
                f"Blocked: {blocked_count}.",
                f"Reserved capital: {total_reserved_capital_usd:.2f} USD.",
            ]
            if merged_issues:
                summary_lines.append(f"Issues surfaced: {len(merged_issues)}.")

        object.__setattr__(self, "allocator_cycle_id", allocator_cycle_id)
        object.__setattr__(self, "allocation_decision_id", allocation_decision_id)
        object.__setattr__(self, "source_store_path", source_store_path)
        object.__setattr__(self, "source_appended_at_utc", source_appended_at_utc)
        object.__setattr__(self, "approved_count", approved_count)
        object.__setattr__(self, "blocked_count", blocked_count)
        object.__setattr__(self, "total_reserved_capital_usd", total_reserved_capital_usd)
        object.__setattr__(self, "items", items)
        object.__setattr__(self, "issues", merged_issues)
        object.__setattr__(self, "summary_lines", summary_lines)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_replay_report_id",
            _stable_id(
                "allocation_replay_report",
                {
                    "allocator_cycle_id": allocator_cycle_id,
                    "allocation_decision_id": allocation_decision_id,
                    "approved_count": approved_count,
                    "blocked_count": blocked_count,
                    "total_reserved_capital_usd": total_reserved_capital_usd,
                    "item_ids": [item.allocation_replay_report_item_id for item in items],
                    "issues": merged_issues,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocator_cycle_id": self.allocator_cycle_id,
            "allocation_decision_id": self.allocation_decision_id,
            "source_store_path": self.source_store_path,
            "source_appended_at_utc": self.source_appended_at_utc,
            "approved_count": self.approved_count,
            "blocked_count": self.blocked_count,
            "total_reserved_capital_usd": self.total_reserved_capital_usd,
            "items": [item.to_dict() for item in self.items],
            "issues": list(self.issues),
            "summary_lines": list(self.summary_lines),
            "metadata": dict(self.metadata),
            "allocation_replay_report_id": self.allocation_replay_report_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationReplayReport":
        if not isinstance(payload, Mapping):
            raise AllocationReplayReportError("payload must be a mapping")
        return cls(
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            allocation_decision_id=payload.get("allocation_decision_id"),
            source_store_path=payload.get("source_store_path"),
            source_appended_at_utc=payload.get("source_appended_at_utc"),
            approved_count=payload.get("approved_count"),
            blocked_count=payload.get("blocked_count"),
            total_reserved_capital_usd=payload.get("total_reserved_capital_usd"),
            items=list(payload.get("items") or []),
            issues=list(payload.get("issues") or []),
            summary_lines=list(payload.get("summary_lines") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_allocation_replay_report(value: Any) -> AllocationReplayReport:
    if isinstance(value, AllocationReplayReport):
        return value
    return AllocationReplayReport.from_dict(_mapping_from_value("allocation_replay_report", value))


def _item_payloads_from_decision_payload(decision_payload: Mapping[str, Any]) -> List[Dict[str, Any]]:
    return [
        *list(decision_payload.get("approved_items") or []),
        *list(decision_payload.get("blocked_items") or []),
    ]


def build_allocation_replay_report_from_snapshot(
    *,
    decision_snapshot: Mapping[str, Any],
    source_store_path: str,
    source_appended_at_utc: str,
    issues: Optional[List[str]] = None,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationReplayReport:
    if not isinstance(decision_snapshot, Mapping):
        raise AllocationReplayReportError("decision_snapshot must be a mapping")

    raw_items = _item_payloads_from_decision_payload(decision_snapshot)
    replay_items: List[AllocationReplayReportItem] = []

    for raw_item in raw_items:
        if not isinstance(raw_item, Mapping):
            raise AllocationReplayReportError("decision items must be mappings")

        candidate_payload = dict(raw_item.get("candidate") or {})
        lineage_payload = dict(candidate_payload.get("lineage") or {})
        lineage_id = lineage_payload.get("allocation_candidate_lineage_id")
        lineage_present = bool(lineage_payload) and isinstance(lineage_id, str) and bool(lineage_id.strip())
        local_issues: List[str] = []
        if not lineage_present:
            local_issues.append("missing lineage from replay source candidate")

        policy_reference = raw_item.get("chain_strategy_budget_policy_id")
        if policy_reference is None:
            policy_reference = candidate_payload.get("chain_strategy_budget_policy_id")

        allocation_candidate_id = raw_item.get("allocation_candidate_id")
        if not isinstance(allocation_candidate_id, str) or not allocation_candidate_id.strip():
            allocation_candidate_id = candidate_payload.get("allocation_candidate_id")
        if not isinstance(allocation_candidate_id, str) or not allocation_candidate_id.strip():
            local_issues.append("candidate field missing from replay source: allocation_candidate_id")
            allocation_candidate_id = _stable_id(
                "replay_candidate",
                {
                    "decision_status": raw_item.get("decision_status"),
                    "raw_item": dict(raw_item),
                },
            )

        replay_items.append(
            AllocationReplayReportItem(
                allocation_candidate_id=allocation_candidate_id,
                decision_status=raw_item.get("decision_status"),
                chain=_resolve_replay_string_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="chain",
                    default_value="unknown",
                    issues=local_issues,
                    transform="lower",
                ),
                strategy_id=_resolve_replay_string_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="strategy_id",
                    default_value="unknown",
                    issues=local_issues,
                    transform="lower",
                ),
                symbol=_resolve_replay_string_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="symbol",
                    default_value="UNKNOWN",
                    issues=local_issues,
                    transform="upper",
                ),
                pair=_resolve_replay_string_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="pair",
                    default_value="UNKNOWN",
                    issues=local_issues,
                    transform="upper",
                ),
                side=_resolve_replay_string_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="side",
                    default_value="UNKNOWN",
                    issues=local_issues,
                    transform="upper",
                ),
                proposed_exposure_usd=_resolve_replay_numeric_field(
                    raw_item=raw_item,
                    candidate_payload=candidate_payload,
                    field_name="proposed_exposure_usd",
                    default_value=0.0,
                    issues=local_issues,
                ),
                reserved_capital_usd=raw_item.get("reserved_capital_usd", 0.0),
                approval_reasons=list(raw_item.get("approval_reasons") or []),
                block_reasons=list(raw_item.get("block_reasons") or []),
                explanation_lines=[],
                lineage_present=lineage_present,
                lineage_id=lineage_id if lineage_present else None,
                policy_reference=policy_reference,
                issues=local_issues,
                metadata=dict(raw_item.get("metadata") or {}),
            )
        )

    merged_issues = list(issues or [])
    return AllocationReplayReport(
        allocator_cycle_id=decision_snapshot.get("allocator_cycle_id"),
        allocation_decision_id=decision_snapshot.get("allocation_decision_id"),
        source_store_path=source_store_path,
        source_appended_at_utc=source_appended_at_utc,
        approved_count=sum(1 for item in replay_items if item.decision_status == "APPROVED"),
        blocked_count=sum(1 for item in replay_items if item.decision_status == "BLOCKED"),
        total_reserved_capital_usd=sum(item.reserved_capital_usd for item in replay_items),
        items=replay_items,
        issues=merged_issues,
        metadata=dict(metadata or {}),
    )


def build_allocation_replay_report_from_store_record(
    *,
    store_record: Any,
    source_store_path: str,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationReplayReport:
    normalized_store_record = _normalize_store_record(store_record)
    decision_snapshot = normalized_store_record.decision.to_dict()
    return build_allocation_replay_report_from_snapshot(
        decision_snapshot=decision_snapshot,
        source_store_path=source_store_path,
        source_appended_at_utc=normalized_store_record.appended_at_utc,
        issues=[],
        metadata=dict(metadata or {}),
    )


def build_allocation_replay_report_by_decision_id(
    *,
    store_path: Any,
    allocation_decision_id: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationReplayReport:
    store_path_str = str(store_path)
    store_record = replay_allocation_decision_by_id(
        store_path=store_path,
        allocation_decision_id=allocation_decision_id,
        strict=True,
    )
    return build_allocation_replay_report_from_store_record(
        store_record=store_record,
        source_store_path=store_path_str,
        metadata=metadata,
    )


def build_allocation_replay_report_by_cycle(
    *,
    store_path: Any,
    allocator_cycle_id: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationReplayReport:
    store_path_str = str(store_path)
    records = replay_allocation_decisions_by_cycle(
        store_path=store_path,
        allocator_cycle_id=allocator_cycle_id,
        strict=True,
    )
    if not records:
        raise AllocationReplayReportError("allocator cycle not found in store")

    issues: List[str] = []
    store_record = records[-1]
    if len(records) > 1:
        issues.append("multiple records found for allocator cycle; latest record was used")

    report = build_allocation_replay_report_from_store_record(
        store_record=store_record,
        source_store_path=store_path_str,
        metadata=metadata,
    )
    if issues:
        payload = report.to_dict()
        payload["issues"] = list(payload.get("issues") or []) + issues
        return AllocationReplayReport.from_dict(payload)
    return report


def render_allocation_replay_report_text(report: Any) -> str:
    normalized_report = normalize_allocation_replay_report(report)

    lines: List[str] = [
        "ALLOCATION REPLAY REPORT",
        "------------------------",
        f"Allocator Cycle : {normalized_report.allocator_cycle_id}",
        f"Decision ID     : {normalized_report.allocation_decision_id}",
        f"Store Path      : {normalized_report.source_store_path}",
        f"Appended At UTC : {normalized_report.source_appended_at_utc}",
        f"Approved        : {normalized_report.approved_count}",
        f"Blocked         : {normalized_report.blocked_count}",
        f"Reserved Capital: {normalized_report.total_reserved_capital_usd:.2f} USD",
        "",
        "SUMMARY",
        "-------",
    ]
    lines.extend(normalized_report.summary_lines)

    if normalized_report.issues:
        lines.extend(["", "ISSUES", "------"])
        lines.extend(f"- {issue}" for issue in normalized_report.issues)

    for index, item in enumerate(normalized_report.items, start=1):
        lines.extend(
            [
                "",
                f"ITEM {index}",
                "------",
                f"Candidate ID : {item.allocation_candidate_id}",
                f"Status       : {item.decision_status}",
                f"Market       : {item.chain} / {item.strategy_id} / {item.symbol} / {item.side}",
                f"Exposure USD : {item.proposed_exposure_usd:.2f}",
                f"Reserved USD : {item.reserved_capital_usd:.2f}",
                f"Lineage      : {'present' if item.lineage_present else 'missing'}",
            ]
        )
        if item.lineage_id:
            lines.append(f"Lineage ID   : {item.lineage_id}")
        if item.policy_reference:
            lines.append(f"Policy Ref   : {item.policy_reference}")

        lines.append("Explanation  :")
        lines.extend(f"  - {line}" for line in item.explanation_lines)

        if item.issues:
            lines.append("Item Issues  :")
            lines.extend(f"  - {issue}" for issue in item.issues)

    return "\n".join(lines) + "\n"
